// 自定义hook：文件存储管理
export var useFileStorage = () => {
  return {
    getCurrentUser,
    getUserStorageKey,
    saveFilesToStorage,
    loadFilesFromStorage,
    saveFileData,
    loadFileData,
    deleteFileData,
    getDefaultFiles,
    getStorageUsage,
    cleanupStorageCenterData
  };
};